using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder: success paths ---

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 9.99m, 3));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(29.97m, order.Total);
        Assert.HasCount(1, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalCorrectly()
    {
        var items = CreateItems(("A", 10m, 2), ("B", 5m, 4));

        var order = _sut.CreateOrder("cust-2", items);

        Assert.AreEqual(40m, order.Total); // (10*2) + (5*4)
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueId()
    {
        var items = CreateItems(("X", 1m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.IsNotEmpty(order.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("X", 1m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    // --- CreateOrder: error paths ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("X", 1m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(() => _sut.CreateOrder("cust-1", []));
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var items = CreateItems(("X", 5m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var found = _sut.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        var items = CreateItems(("X", 1m, 1));
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-B", items);

        var results = _sut.GetOrdersByCustomer("cust-A");

        Assert.HasCount(2, results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var results = _sut.GetOrdersByCustomer("nobody");

        Assert.IsEmpty(results);
    }

    // --- Data-driven: total calculation ---

    [TestMethod]
    [DataRow(10, 1, 10, DisplayName = "Single unit")]
    [DataRow(7, 3, 21, DisplayName = "Multiple units")]
    [DataRow(0, 5, 0, DisplayName = "Zero price")]
    public void CreateOrder_CalculatesTotal(double price, int qty, double expectedTotal)
    {
        var items = CreateItems(("Item", (decimal)price, qty));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }
}

